// n8n Code Node - 解碼中文 Subject
const subject = $input.first().json.headers.subject;

function decodeSubject(encodedSubject) {
  if (!encodedSubject) return '';

  try {
    // 1. 處理 MIME 編碼 (=?UTF-8?B?...?= 或 =?UTF-8?Q?...?=)
    if (encodedSubject.includes('=?UTF-8?B?')) {
      return encodedSubject.replace(/=\?UTF-8\?B\?([^?]+)\?=/g, (match, encoded) => {
        return Buffer.from(encoded, 'base64').toString('utf-8');
      });
    }

    if (encodedSubject.includes('=?UTF-8?Q?')) {
      return encodedSubject.replace(/=\?UTF-8\?Q\?([^?]+)\?=/g, (match, encoded) => {
        // Quoted-Printable 解碼
        return encoded.replace(/=([0-9A-F]{2})/g, (match, hex) => {
          return String.fromCharCode(parseInt(hex, 16));
        }).replace(/_/g, ' ');
      });
    }

    // 2. 嘗試 Base64 解碼
    try {
      const decoded = Buffer.from(encodedSubject, 'base64').toString('utf-8');
      // 檢查是否包含中文字元
      if (/[\u4e00-\u9fff]/.test(decoded)) {
        return decoded;
      }
    } catch (e) {
      // Base64 解碼失敗，繼續其他方法
    }

    // 3. 嘗試 URL 解碼
    try {
      const urlDecoded = decodeURIComponent(encodedSubject);
      if (urlDecoded !== encodedSubject) {
        return urlDecoded;
      }
    } catch (e) {
      // URL 解碼失敗
    }

    // 4. 如果都不是，直接返回原始字串
    return encodedSubject;

  } catch (error) {
    console.error('解碼 subject 時發生錯誤:', error);
    return encodedSubject;
  }
}

const decodedSubject = decodeSubject(subject);

return [{
  json: {
    ...($input.first().json),
    headers: {
      ...($input.first().json.headers),
      subject: decodedSubject,
      originalSubject: subject
    },
    decodedSubject: decodedSubject
  }
}];

// n8n Code Node - 提取 YouTube 網址
// 假設輸入資料在 'text' 欄位中

// 從輸入項目取得文字內容
const inputText = $input.first().json.text;

// 如果沒有輸入文字，回傳空結果
if (!inputText) {
  return [{ json: { youtubeUrl: '', found: false } }];
}

// YouTube 網址的正則表達式模式
const youtubeRegex = /https?:\/\/(?:www\.|m\.)?(?:youtube\.com|youtu\.be)\/(?:watch\?v=|embed\/|v\/|shorts\/|playlist\?list=)?([a-zA-Z0-9_-]{11}|[a-zA-Z0-9_-]+)/g;

// 更廣泛的 YouTube 網址模式（包含各種格式）
const broadYoutubeRegex = /https?:\/\/(?:www\.|m\.)?(?:youtube\.com|youtu\.be)\/[^\s\n\r]+/g;

// 尋找所有 YouTube 網址
const matches = inputText.match(broadYoutubeRegex);

let result = {
  youtubeUrl: '',
  found: false,
  allUrls: []
};

if (matches && matches.length > 0) {
  result.youtubeUrl = matches[0]; // 取得第一個找到的網址
  result.found = true;
  result.allUrls = matches; // 儲存所有找到的網址

  // 清理網址（移除可能的尾隨字元）
  result.youtubeUrl = result.youtubeUrl.replace(/[.,;!?]*$/, '');
}

// 如果使用廣泛模式沒找到，嘗試更簡單的模式
if (!result.found) {
  const simpleMatch = inputText.match(/youtube\.com\/shorts\/[^\s\n\r]+/);
  if (simpleMatch) {
    result.youtubeUrl = 'https://' + simpleMatch[0];
    result.found = true;
    result.allUrls = [result.youtubeUrl];
  }
}

// 回傳結果
return [{ 
  json: { 
    ...result,
    originalText: inputText
  } 
}];

