// 遍歷所有輸入項目
for (const item of $input.all()) {
  // 取得 subject 欄位
  const subject = item.json.subject;

  if (subject) {
    // 使用正則表達式匹配 "Keto" 後面的數字
    // 匹配模式：Keto 後面跟著空格，然後是浮點數，再跟著空格和整數
    const regex = /keto\s+(\d+\.?\d*)\s+(\d+)/i;
    const match = subject.match(regex);

    if (match) {
      // match[1] 是第一個數字（浮點數）
      // match[2] 是第二個數字（整數）
      item.json.firstNumber = match[1];  // "5.0"
      item.json.secondNumber = match[2]; // "80"

      // 如果需要轉換為實際的數值類型
      item.json.firstNumberFloat = parseFloat(match[1]);  // 5.0
      item.json.secondNumberInt = parseInt(match[2]);     // 80
    } else {
      // 如果沒有匹配到，設置預設值或錯誤訊息
      item.json.firstNumber = null;
      item.json.secondNumber = null;
      item.json.error = "無法從 subject 中找到 Keto 後面的數字";
    }
  } else {
    item.json.error = "缺少 subject 欄位";
  }
}

return $input.all();

